module.exports = async function (context, req) {
    const { CosmosClient } = require("@azure/cosmos");
    const client = new CosmosClient(process.env.CosmosDBConnection);
    const database = client.database(process.env.DatabaseName);
    const container = database.container(process.env.ContainerName);
    
    context.log('Starting batch processing function');
    
    try {
        const batchSize = 1000;
        let continuationToken = null;
        let processedCount = 0;
        
        do {
            const query = {
                query: "SELECT * FROM c",
                parameters: []
            };
            
            const options = {
                pageSize: batchSize,
                enableCrossPartitionQuery: true
            };
            
            if (continuationToken) {
                options.continuation = continuationToken;
            }
            
            const { resources, responseHeaders } = await container.items.query(query, options);
            
            if (resources.length > 0) {
                // Process batch
                for (const item of resources) {
                    try {
                        // Your processing logic here
                        await processItem(item);
                        processedCount++;
                    } catch (error) {
                        context.log.error(`Error processing item ${item.id}:`, error);
                        // Continue with other items
                    }
                }
                
                context.log(`Processed batch. Total processed: ${processedCount}`);
            }
            
            continuationToken = responseHeaders['x-ms continuation'];
            
            // Check if we've been running for too long
            if (context.executionContext.remainingTimeInMs < 30000) {
                context.log('Approaching timeout, will continue processing');
                // Continue processing to avoid interruption
            }
            
        } while (continuationToken);
        
        context.log(`Batch processing completed. Total items processed: ${processedCount}`);
        context.res = {
            status: 200,
            body: {
                message: "Batch processing completed",
                totalProcessed: processedCount
            }
        };
        
    } catch (error) {
        context.log.error('Batch processing error:', error);
        context.res = {
            status: 500,
            body: {
                error: error.message
            }
        };
    }
};

